import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FiShield, 
  FiArrowLeft, 
  FiCalendar, 
  FiClock, 
  FiMapPin, 
  FiDollarSign,
  FiCheckCircle,
  FiXCircle,
  FiClock as FiPending,
  FiStar
} from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import { Booking } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';

const BookingHistory: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [activeFilter, setActiveFilter] = useState<'all' | 'pending' | 'accepted' | 'completed' | 'cancelled'>('all');

  // Fetch bookings
  const sessionId = localStorage.getItem('sessionId');
  interface BookingApiResponseOuter {
    status: string;
    data: {
      user: any;
      summary: any;
      bookings: {
        active: any[];
        completed: any[];
      };
    };
  }
  const { data: bookingsData, isLoading, refetch } = useQuery<BookingApiResponseOuter>(
    'bookings',
    async () => {
      return await apiService.get<BookingApiResponseOuter>(
        `${API_ENDPOINTS.USER_BOOKINGS}?session_id=${sessionId}`
      );
    },
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load bookings');
      }
    }
  );

  // Use correct structure from API response
  const activeBookings: any[] = bookingsData?.data?.bookings?.active || [];
  const completedBookings: any[] = bookingsData?.data?.bookings?.completed || [];

  // Debug log for data
  console.log('bookingsData:', bookingsData);

  // Filtered bookings based on activeFilter
  let filteredBookings: any[] = [];
  if (activeFilter === 'all') {
    filteredBookings = [...activeBookings, ...completedBookings];
  } else if (activeFilter === 'pending' || activeFilter === 'accepted') {
    filteredBookings = activeBookings.filter((booking: any) => booking.status === activeFilter);
  } else if (activeFilter === 'completed') {
    filteredBookings = completedBookings;
  } else if (activeFilter === 'cancelled') {
    filteredBookings = activeBookings.filter((booking: any) => booking.status === 'cancelled');
  }

  // Debug logs
  console.log('bookingsData:', bookingsData);
  console.log('activeBookings:', activeBookings);
  console.log('completedBookings:', completedBookings);
  console.log('filteredBookings:', filteredBookings);

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'completed':
        return <FiCheckCircle className="w-5 h-5 text-green-500" />;
      case 'accepted':
        return <FiClock className="w-5 h-5 text-blue-500" />;
      case 'pending':
        return <FiPending className="w-5 h-5 text-yellow-500" />;
      case 'cancelled':
        return <FiXCircle className="w-5 h-5 text-red-500" />;
      default:
        return <FiClock className="w-5 h-5 text-gray-500" />;
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
        return 'bg-green-100 text-green-800';
      case 'accepted':
        return 'bg-blue-100 text-blue-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'cancelled':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  const handleCancelBooking = async (bookingId: string) => {
    try {
      const response = await apiService.post(API_ENDPOINTS.CANCEL_BOOKING, {
        booking_id: bookingId
      });

      if (response.status === 'success') {
        toast.success('Booking cancelled successfully');
        refetch();
      } else {
        toast.error(response.message || 'Failed to cancel booking');
      }
    } catch (error) {
      toast.error('Failed to cancel booking');
    }
  };

  const filterOptions = [
    { value: 'all', label: 'All Bookings', count: (bookingsData?.data?.bookings?.active?.length || 0) + (bookingsData?.data?.bookings?.completed?.length || 0) },
    { value: 'pending', label: 'Pending', count: activeBookings.filter((b: any) => b.status === 'pending').length },
    { value: 'accepted', label: 'Accepted', count: activeBookings.filter((b: any) => b.status === 'accepted').length },
    { value: 'completed', label: 'Completed', count: completedBookings.length },
    { value: 'cancelled', label: 'Cancelled', count: activeBookings.filter((b: any) => b.status === 'cancelled').length },
  ];

  // Minimal render for debugging
  return (
    <div>
      <h2>Booking History</h2>
      {filteredBookings.length === 0 ? (
        <div>No bookings found.</div>
      ) : (
        filteredBookings.map((booking: any) => (
          <div key={booking.booking_id}>
            {booking.service_name} - {booking.booking_id} - {booking.status}
          </div>
        ))
      )}
    </div>
  );
};

export default BookingHistory;
